SELECT name, description 
FROM columns 
WHERE table_id = (SELECT table_id FROM tables WHERE name = 'orders');

SELECT name, data_type, nullable, default_value
FROM columns
ORDER BY data_type;

SELECT created_by, COUNT(*) AS label_count
FROM labels
GROUP BY created_by;

SELECT name, primary_key
FROM tables
WHERE updated_by = 1;

SELECT tables.*, columns.*
FROM tables
JOIN columns ON tables.table_id = columns.table_id;

SELECT AVG(rule_count) AS average_validation_rules_per_column
FROM (
    SELECT COUNT(*) AS rule_count
    FROM validation_rules
    GROUP BY column_id
);
